parameters.text:
=🚨 MALICIOUS FILE DETECTED
Hash: {{ $json.hash }}
Detections: {{$json.malicious}}/{{$json.total}}
Family: {{$json.malware_family}}

parameters.jsCode:
const stats = $json.data.attributes.last_analysis_stats;

const malicious = stats.malicious || 0;
const suspicious = stats.suspicious || 0;
const total = Object.values(stats).reduce((a, b) => a + b, 0);

let verdict = "Clean";
if (malicious > 0) verdict = "Malicious";
else if (suspicious > 0) verdict = "Suspicious";

return [{
  json: {    
    hash: $json.data.id,
    verdict,
    malicious,
    suspicious,
    total,
    malware_family: $json.data.attributes.popular_threat_classification?.suggested_threat_label || "N/A"
  }
}];

