={{
 $json.verdict === 'Suspicious'
    ? `⚠️ *SUSPICIOUS FILE*
Hash: ${$json.hash}
Detections: ${$json.suspicious}/${$json.total}`

  : $json.verdict === 'Clean'
    ? `✅ *CLEAN FILE*
